class Solution:
    def isGoodArray(self, nums) -> bool:
        from math import gcd
        g = 0
        for x in nums:
            g = gcd(g, x)
            if g == 1:
                return True
        return g == 1

solutions.javascript:
var isGoodArray = function(nums) {
    function gcd(a, b) { while (b) { [a, b] = [b, a % b]; } return a; }
    let g = 0;
    for (const x of nums) {
        g = gcd(g, x);
        if (g === 1) return true;
    }
    return g === 1;
};
